#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//--ATI-like vUv edge ranging----------------
vUv=vec2(mix(vUv.x,1,vUv.x>1),mix(vUv.y,1,vUv.y>1));
vUv=vec2(mix(vUv.x,0,vUv.x<0),mix(vUv.y,0,vUv.y<0));

//--Brightnhess UV control (shift)----------
ret = GetPixel(mix(vUvOriginal,vUv,dot(GetPixel(vUv),GetBlur1(vUv))));

//--Color/luminosity split by Fed-----------
vec3 ret1 = vec3(GetPixel(mix(vUvOriginal,vUv,0.3+q4*0.06*abs(rot_d1[1].x))).x,
                     GetPixel(mix(vUvOriginal,vUv,0.3+q4*0.06*abs(rot_d1[1].y))).y,
                     GetPixel(mix(vUvOriginal,vUv,0.3+q4*0.06*abs(rot_d1[1].z))).z);
float li = min(min(ret.x,ret.y),ret.z); //lum
float li1 = min(min(ret1.x,ret1.y),ret1.z);
vec3 col = ret1-li1; //hue
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y += (noise9).x*.5;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z += (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x += (noise9).z*.5;
ret=vec3(q3,q1,q2)*li+col*1.01;
//------------------------------------------

ret=pow(ret,ret.zxy+0.8); //shit!
ret=ret-0.002;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 ac = vec2(q1,q2);
vec2 mu = vec2(q3,q4);
vec2 c = vec2(q5,q6);
vec2 d = vec2(q7,q8);

vec2 z = (vUv-0.5)*uAspect.wz;

// (c*z + d)
vec2 czd = vec2(z.x*c.x-z.y*c.y,z.x*c.y-z.y*c.x)*uAspect.yx + d;
// mu/(cz+d)
vec2 moebius = vec2( mu.x*czd.x + mu.y*czd.y , mu.y*czd.x-mu.x*czd.y )/(czd.x*czd.x+czd.y*czd.y) + ac;

    d = uTexSize.zw*4;
    vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

moebius = 0.5 + (1.0 - abs( fract( moebius * 0.5  - vec2(dx.y,dy.y)*0.2 + vec2(dx.x,dy.x)*0.1) * 2 - 1.0 )-0.5)*0.99;

ret = tex2d(sampler_rand00, fract(moebius));
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((moebius.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;
ret-=slow_roam_sin.zyx*slow_roam_cos.ywx*.4;
ret = mix(ret,-2,GetPixel(vUv + vec2(dx.y,dy.y)*0.1).x*0.1);
ret = mix(ret,-1,GetPixel(vUv - vec2(dx.z,dy.z)*0.024).z*0.4);
ret = mix(ret,1,clamp01(GetPixel(vUv).y-GetBlur3(vUv).y*2));
//ret = GetPixel(vUv).x;

  fragColor = ret;
}
